INSERT INTO question_bank (id, mission_id, question_type, prompt, options, content_tags, curriculum_ref, difficulty, source_type, generation_phase, pack_no, difficulty_band, question_pool_status, is_active) VALUES
    ('ae8d7e0d-89d9-3d3d-aa4b-b42e59aec305', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'OX', '등교길에 본 도구를 떠올리며 판단해 보세요. 스마트 스피커, 번역 앱, 카메라 앱처럼 우리 생활 속 여러 도구에 인공지능이 쓰일 수 있어요.', NULL, '[ "FACT", "SAFETY" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 1, 'LOW', 'ACTIVE', TRUE),
    ('0031da4f-c47a-3cad-b07a-1fd5862c9782', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'OX', '등교길에 본 도구를 떠올리며 판단해 보세요. 계산이 빠르기만 하면 모두 인공지능이라고 볼 수 있어요.', NULL, '[ "FACT", "VERIFICATION" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 1, 'LOW', 'ACTIVE', TRUE),
    ('86fcf72b-bbb4-3287-a9d8-c52062064cf7', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'MULTIPLE', '학교에서 자주 보는 예를 떠올리며 골라 보세요. 다음 중 생활 속 인공지능 사례로 가장 알맞은 것은 무엇일까요?', '[ "빈 공책", "꽃을 구별해 주는 카메라 앱", "색종이를 접는 종이 설명서", "바람개비 장난감" ]', '[ "FACT", "VERIFICATION" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 1, 'LOW', 'ACTIVE', TRUE),
    ('c25fe073-0389-3ba9-9954-38ce388e8805', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'MULTIPLE', '학교에서 자주 보는 예를 떠올리며 골라 보세요. Quick Draw를 해 보면서 알 수 있는 점으로 가장 알맞은 것은 무엇일까요?', '[ "사람 마음을 그대로 읽어요.", "선의 특징을 보고 무엇인지 짐작해요.", "한 번 배우면 절대 틀리지 않아요.", "그림을 안 보고 무작정 정답을 말해요." ]', '[ "FACT", "PROMPT" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'MEDIUM', 'GPT', 'PREGENERATED', 1, 'MEDIUM', 'ACTIVE', TRUE),
    ('6feffb52-8d58-325d-93c6-8c14764a4fdb', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'MULTIPLE', '학교에서 자주 보는 예를 떠올리며 골라 보세요. 생활 속 여러 사례를 볼 때 먼저 생각하면 좋은 질문은 무엇일까요?', '[ "버튼이 많으면 더 똑똑할까?", "겉모양이 예쁘면 모두 AI일까?", "전기가 들어오면 모두 AI일까?", "이 도구는 무엇을 도와줄까?" ]', '[ "PROMPT", "FACT" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 1, 'LOW', 'ACTIVE', TRUE),
    ('fb67594d-a460-3fd6-8867-31fda2ba710a', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'FILL', '수업에서 본 예를 떠올리며 빈칸을 채워 보세요. 우리 생활 속 인공지능을 찾을 때는 겉모습보다 어떤 ____을 하는지 살펴봐요.', '[ "가격", "기능", "무게", "색깔" ]', '[ "FACT", "VERIFICATION" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 1, 'LOW', 'ACTIVE', TRUE),
    ('1d56b048-e383-3b0c-8191-2a7f4d0163bc', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'FILL', '수업에서 본 예를 떠올리며 빈칸을 채워 보세요. 여러 인공지능 사례를 보고 공통점을 찾으려면 사례를 ____ 해 보아야 해요.', '[ "삭제", "복사", "숨기", "비교" ]', '[ "VERIFICATION", "FACT" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'MEDIUM', 'GPT', 'PREGENERATED', 1, 'MEDIUM', 'ACTIVE', TRUE),
    ('54252005-07fd-3e4b-a1c4-404908c372ae', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'SITUATION', '친구가 번역 앱, 카메라 앱, 알람 시계를 보여 주며 "셋 다 인공지능이야"라고 말했어요. 어떻게 말해 주는 것이 좋을까요?', '[ "이름이 어려우면 모두 인공지능이라고 하면 돼.", "배터리가 들어가면 모두 인공지능이라고 보면 돼.", "겉모양이 비슷하면 같은 종류라고 생각하면 돼.", "도구 기능부터 살펴보자고 해." ]', '[ "VERIFICATION", "FACT" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'HIGH', 'GPT', 'PREGENERATED', 1, 'HIGH', 'ACTIVE', TRUE),
    ('a2d85886-ca7a-3a77-a5d2-b3e010e1b700', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'SITUATION', 'Quick Draw에서 같은 고양이 그림을 그렸는데 한 번은 "고양이", 한 번은 "여우"라고 나왔어요. 가장 알맞은 생각은 무엇일까요?', '[ "비슷한 그림은 헷갈릴 수 있다고 생각하면 돼요.", "한 번 틀렸으니 다시 쓰면 안 된다고 보면 돼요.", "사람을 속이려고 일부러 틀렸다고 생각하면 돼요.", "답이 바뀌면 기계가 완전히 고장 난 거라고 보면 돼요." ]', '[ "FACT", "VERIFICATION" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'HIGH', 'GPT', 'PREGENERATED', 1, 'HIGH', 'ACTIVE', TRUE),
    ('9b9656ad-fc90-3f1f-ad17-f8491b60347b', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'SITUATION', '"분실물 찾기 도우미" 같은 인공지능 도우미를 구상하고 있어요. 가장 먼저 함께 생각하면 좋을 것은 무엇일까요?', '[ "이름부터 멋지게 정하고 기능은 나중에 생각해요.", "누구를 돕고 어떤 문제를 풀지 먼저 정해요.", "친구 아이디어를 그대로 따라 하면 된다고 생각해요.", "재미있는 기능만 떠올리고 쓰임은 나중에 봐요." ]', '[ "PROMPT", "SAFETY" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'MEDIUM', 'GPT', 'PREGENERATED', 1, 'MEDIUM', 'ACTIVE', TRUE),
    ('37047933-e370-3910-9aa3-325dcc9ad623', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'OX', '수업 활동 장면을 떠올리며 판단해 보세요. 스마트 스피커, 번역 앱, 카메라 앱처럼 생활 속 여러 도구에 인공지능이 쓰일 수 있어요.', NULL, '[ "FACT", "SAFETY" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 2, 'LOW', 'ACTIVE', TRUE),
    ('54d2f0e9-b5df-329d-a07c-d342e7a7eabe', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'OX', '수업 활동 장면을 떠올리며 판단해 보세요. 전기가 들어간다고 해서 모든 기계를 인공지능이라고 하지는 않아요.', NULL, '[ "FACT", "VERIFICATION" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 2, 'LOW', 'ACTIVE', TRUE),
    ('93bd6a28-ba20-3458-9c60-bd214acbe976', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'MULTIPLE', '수업 활동 속 예를 떠올리며 골라 보세요. 다음 중 생활 속 인공지능 사례로 알맞은 보기를 고르세요.', '[ "빈 공책", "바람개비 장난감", "꽃을 구별해 주는 카메라 앱", "색종이를 접는 종이 설명서" ]', '[ "FACT", "VERIFICATION" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 2, 'LOW', 'ACTIVE', TRUE),
    ('6bcced99-3c27-3a25-981f-918396a39a07', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'MULTIPLE', '수업 활동 속 예를 떠올리며 골라 보세요. 그림 분류 활동을 해 보면서 알 수 있는 점으로 알맞은 보기를 고르세요.', '[ "한 번 배우면 절대 틀리지 않아요.", "사람 마음을 바로 읽어요.", "인공지능은 그림을 보지 않고 무작정 정답을 이야기해요.", "선의 특징을 보고 무엇인지 짐작해요." ]', '[ "FACT", "PROMPT" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'MEDIUM', 'GPT', 'PREGENERATED', 2, 'MEDIUM', 'ACTIVE', TRUE),
    ('0af66cac-57dc-3228-9d65-db980d8296ad', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'MULTIPLE', '수업 활동 속 예를 떠올리며 골라 보세요. 생활 속 여러 사례를 볼 때 먼저 생각하면 좋은 질문은 무엇인가요?', '[ "이 도구는 무엇을 도와줄까?", "버튼이 많으면 더 똑똑할까?", "겉모양이 예쁘면 모두 AI일까?", "전기가 들어오면 모두 AI일까?" ]', '[ "PROMPT", "FACT" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 2, 'LOW', 'ACTIVE', TRUE),
    ('762c850e-38aa-3ac9-9df6-910245610b50', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'FILL', '활동 장면을 떠올리며 빈칸을 채워 보세요. 생활 속 인공지능을 찾을 때는 겉모습보다 어떤 ____을 하는지 살펴봐요.', '[ "무게", "가격", "색깔", "기능" ]', '[ "FACT", "VERIFICATION" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 2, 'LOW', 'ACTIVE', TRUE),
    ('9f23815b-08cd-36ef-8a41-ed066642b4b4', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'FILL', '활동 장면을 떠올리며 빈칸을 채워 보세요. 생활 속 AI 도구의 닮은 점을 찾으려면 서로 ____ 해 보아야 해요.', '[ "숨기", "삭제", "비교", "복사" ]', '[ "VERIFICATION", "FACT" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'MEDIUM', 'GPT', 'PREGENERATED', 2, 'MEDIUM', 'ACTIVE', TRUE),
    ('7073b959-fbd5-38b8-98e7-7579b4fe8738', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'SITUATION', '수업 시간에 친구가 음성 입력 기능, 사진 분류 앱, 손전등 앱을 보여 주며 "셋 다 인공지능이야"라고 말했어요. 가장 알맞은 대답은 무엇일까요?', '[ "도구 기능부터 살펴보자고 해.", "이름이 어려우면 모두 인공지능이라고 하면 돼.", "배터리가 들어가면 모두 인공지능이라고 보면 돼.", "겉모양이 비슷하면 같은 종류라고 생각하면 돼." ]', '[ "VERIFICATION", "FACT" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'HIGH', 'GPT', 'PREGENERATED', 2, 'HIGH', 'ACTIVE', TRUE),
    ('90018489-3cd0-3c37-b2f0-fe207e080450', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'SITUATION', '실험을 하다가 그림 분류 활동에서 같은 강아지 그림을 그렸는데 한 번은 "강아지", 한 번은 "늑대"라고 나왔어요. 어떤 생각이 가장 적절할까요?', '[ "한 번 틀렸으니 다시 쓰면 안 된다고 보면 돼요.", "사람을 속이려고 일부러 틀렸다고 생각하면 돼요.", "비슷한 그림은 헷갈릴 수 있다고 생각하면 돼요.", "답이 바뀌면 기계가 완전히 고장 난 거라고 보면 돼요." ]', '[ "FACT", "VERIFICATION" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'HIGH', 'GPT', 'PREGENERATED', 2, 'HIGH', 'ACTIVE', TRUE),
    ('a61c63f8-79d6-3c28-8e84-88b82389ad1c', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'SITUATION', '모둠 계획을 세우는 중 "학교 식물 물주기 도우미" 같은 인공지능 도우미를 구상하고 있어요. 출발점으로 가장 알맞은 것은 무엇일까요?', '[ "이름부터 멋지게 정하고 기능은 나중에 생각해요.", "친구 아이디어를 그대로 따라 하면 된다고 생각해요.", "재미있는 기능만 떠올리고 쓰임은 나중에 봐요.", "누구를 돕고 어떤 문제를 풀지 먼저 정해요." ]', '[ "PROMPT", "SAFETY" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'MEDIUM', 'GPT', 'PREGENERATED', 2, 'MEDIUM', 'ACTIVE', TRUE),
    ('4307e7ad-8e84-3c1c-b2dc-d04803bead9c', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'OX', '모둠 토의 중이라고 생각하며 판단해 보세요. 스마트 스피커, 번역 앱, 카메라 앱처럼 일상에서 여러 도구에 인공지능이 쓰이기도 해요.', NULL, '[ "FACT", "SAFETY" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 3, 'LOW', 'ACTIVE', TRUE),
    ('aa4640ee-a67e-358a-b814-c1bcb7e930b3', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'OX', '모둠 토의 중이라고 생각하며 판단해 보세요. 버튼이 많다고 해서 모두 인공지능인 것은 아니에요.', NULL, '[ "FACT", "VERIFICATION" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 3, 'LOW', 'ACTIVE', TRUE),
    ('6be5e29f-4e45-3860-847f-f8c2348c235e', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'MULTIPLE', '모둠 토의에서 나온 예를 떠올리며 골라 보세요. 다음 중 생활 속 인공지능 사례로 맞는 것을 고르세요.', '[ "색종이를 접는 종이 설명서", "꽃을 구별해 주는 카메라 앱", "바람개비 장난감", "빈 공책" ]', '[ "FACT", "VERIFICATION" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 3, 'LOW', 'ACTIVE', TRUE),
    ('812143e1-107b-3636-96d3-c8eb13e39ee0', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'MULTIPLE', '모둠 토의에서 나온 예를 떠올리며 골라 보세요. 간단한 낙서 분류 도구를 해 보면서 알 수 있는 점으로 맞는 것을 고르세요.', '[ "그림을 안 보고 무작정 정답을 말해 봐요.", "선의 특징을 보고 무엇인지 짐작해요.", "사람 마음을 그냥 읽어요.", "한 번 배우면 절대 틀리지 않아요." ]', '[ "FACT", "PROMPT" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'MEDIUM', 'GPT', 'PREGENERATED', 3, 'MEDIUM', 'ACTIVE', TRUE),
    ('9082ecdf-f2ae-3d1b-8357-3c02203c571c', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'MULTIPLE', '모둠 토의에서 나온 예를 떠올리며 골라 보세요. 생활 속 여러 사례를 볼 때 먼저 생각하면 좋은 질문은 무엇인지 고르세요.', '[ "버튼이 많으면 더 똑똑할까?", "겉모양이 예쁘면 모두 AI일까?", "이 도구는 무엇을 도와줄까?", "전기가 들어오면 모두 AI일까?" ]', '[ "PROMPT", "FACT" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 3, 'LOW', 'ACTIVE', TRUE),
    ('cef026d5-0bed-3337-9f96-eab8e28f2ce3', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'FILL', '모둠 대화 속 예를 떠올리며 빈칸을 채워 보세요. 일상에서 인공지능을 찾을 때는 겉모습보다 어떤 ____을 하는지 살펴봐요.', '[ "기능", "색깔", "가격", "무게" ]', '[ "FACT", "VERIFICATION" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 3, 'LOW', 'ACTIVE', TRUE),
    ('484477be-739d-3474-b3e1-c431939b7567', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'FILL', '모둠 대화 속 예를 떠올리며 빈칸을 채워 보세요. 비슷한 앱과 기계를 구별하려면 사례를 나란히 놓고 ____ 해야 해요.', '[ "복사", "비교", "삭제", "숨기" ]', '[ "VERIFICATION", "FACT" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'MEDIUM', 'GPT', 'PREGENERATED', 3, 'MEDIUM', 'ACTIVE', TRUE),
    ('d036d4a6-1d16-363b-b718-8df1ba86a0a0', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'SITUATION', '모둠 토의에서 친구가 음악 추천 앱, 식물 인식 앱, 타이머를 보여 주며 "셋 다 인공지능이야"라고 말했어요. 어떤 설명이 가장 좋을까요?', '[ "이름이 어려우면 모두 인공지능이라고 하면 돼.", "배터리가 들어가면 모두 인공지능이라고 보면 돼.", "도구 기능부터 살펴보자고 해.", "겉모양이 비슷하면 같은 종류라고 생각하면 돼." ]', '[ "VERIFICATION", "FACT" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'HIGH', 'GPT', 'PREGENERATED', 3, 'HIGH', 'ACTIVE', TRUE),
    ('46da1668-4a6e-36e3-a404-2ae0d0eab22f', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'SITUATION', '활동 중에 간단한 낙서 분류 도구에서 같은 사과 그림을 그렸는데 한 번은 "사과", 한 번은 "토마토"라고 나왔어요. 어떻게 이해하는 것이 좋을까요?', '[ "비슷한 그림은 헷갈릴 수 있다고 생각하면 돼요.", "한 번 틀렸으니 다시 쓰면 안 된다고 보면 돼요.", "사람을 속이려고 일부러 틀렸다고 생각하면 돼요.", "답이 바뀌면 기계가 완전히 고장 난 거라고 보면 돼요." ]', '[ "FACT", "VERIFICATION" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'HIGH', 'GPT', 'PREGENERATED', 3, 'HIGH', 'ACTIVE', TRUE),
    ('b05a78ca-02d4-32aa-9240-e5c2afd372a3', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'SITUATION', '아이디어를 정리하다가 "도서관 책 추천 도우미" 같은 인공지능 도우미를 구상하고 있어요. 먼저 결정하면 좋을 것은 무엇일까요?', '[ "이름부터 멋지게 정하고 기능은 나중에 생각해요.", "누구를 돕고 어떤 문제를 풀지 먼저 정해요.", "친구 아이디어를 그대로 따라 하면 된다고 생각해요.", "재미있는 기능만 떠올리고 쓰임은 나중에 봐요." ]', '[ "PROMPT", "SAFETY" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'MEDIUM', 'GPT', 'PREGENERATED', 3, 'MEDIUM', 'ACTIVE', TRUE),
    ('6fba2a87-0647-3cc0-b621-602d856b5f87', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'OX', '발표를 준비하는 장면을 떠올리며 판단해 보세요. 스마트 스피커, 번역 앱, 카메라 앱처럼 생활 속 여러 곳에서 여러 도구에 인공지능이 쓰일 수 있어요.', NULL, '[ "FACT", "SAFETY" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 4, 'LOW', 'ACTIVE', TRUE),
    ('64cac55a-b61f-3194-8c28-73b899af0529', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'OX', '발표를 준비하는 장면을 떠올리며 판단해 보세요. 소리가 나온다고 해서 다 인공지능이라고 볼 수는 없어요.', NULL, '[ "FACT", "VERIFICATION" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 4, 'LOW', 'ACTIVE', TRUE),
    ('b95a3a93-eebf-39dc-a7c0-2ec4f02e9f4c', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'MULTIPLE', '발표 준비 장면을 떠올리며 골라 보세요. 다음 중 생활 속 인공지능 사례로 가장 알맞은 설명은 무엇인가요?', '[ "바람개비 장난감", "색종이를 접는 종이 설명서", "빈 공책", "꽃을 구별해 주는 카메라 앱" ]', '[ "FACT", "VERIFICATION" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 4, 'LOW', 'ACTIVE', TRUE),
    ('7a627eca-fa0c-3c9c-92c1-4f4119edf83f', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'MULTIPLE', '발표 준비 장면을 떠올리며 골라 보세요. 그림 맞히기 도구를 해 보면서 알 수 있는 점으로 가장 알맞은 설명은 무엇인가요?', '[ "인공지능은 그림을 보지 않고 무작정 정답을 설명해요.", "한 번 배우면 절대 틀리지 않아요.", "인공지능은 사람의 마음을 있는 그대로 읽어요.", "선의 특징을 보고 무엇인지 짐작해요." ]', '[ "FACT", "PROMPT" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'MEDIUM', 'GPT', 'PREGENERATED', 4, 'MEDIUM', 'ACTIVE', TRUE),
    ('8fa89be8-4689-32ad-bfa8-a6bfec23686c', '86157cba-318c-3d6c-ab8a-580b1323ff7c', 'MULTIPLE', '발표 준비 장면을 떠올리며 골라 보세요. 생활 속 여러 사례를 볼 때 먼저 생각하면 알맞은 질문은 무엇인가요?', '[ "이 도구는 무엇을 도와줄까?", "버튼이 많으면 더 똑똑할까?", "겉모양이 예쁘면 모두 AI일까?", "전기가 들어오면 모두 AI일까?" ]', '[ "PROMPT", "FACT" ]', 'KERIS-1 Ch2.1 pp.27-29; Ch3.1 pp.83-96; D0qG389 STEP 1', 'LOW', 'GPT', 'PREGENERATED', 4, 'LOW', 'ACTIVE', TRUE),
