    ('8c0e6c37-17be-3bab-b5df-02ea27a6f53c', '5f01b2ce-caf2-3045-8aac-59f35fa5bc55', 'SITUATION', '새 자료를 넣었더니 모둠에서 "모두가 쉽게 동의하지 못하는 선택" 같은 어려운 질문이 나왔어요. 이때 어떤 생각이 좋을까요?', '[ "어려운 질문이니 그냥 장난처럼 넘겨요.", "한 사람 의견만 바로 정답으로 정해요.", "쉽게 답이 나지 않는 이유를 함께 말해 봐요.", "누가 영향을 받는지는 생각하지 않아요." ]', '[ "PROMPT", "VERIFICATION" ]', 'KERIS-1 Ch4.3 pp.179-191', 'MEDIUM', 'GPT', 'PREGENERATED', 6, 'MEDIUM', 'ACTIVE', TRUE),
    ('2c1485a7-dba3-303a-9c7b-ff782275e7ea', '5f01b2ce-caf2-3045-8aac-59f35fa5bc55', 'SITUATION', '계획을 짜는 중 학교에서 "자동 벌점 기록 시스템"을 도입하자는 의견이 나왔어요. 시작점으로 가장 알맞은 것은 무엇일까요?', '[ "편리하기만 하면 다른 점은 보지 않아도 될까요?", "새 기술이니 바로 들여오면 될까요?", "반대 의견은 듣지 않아도 될까요?", "누가 도움을 받고 누가 불편해질지 따져 볼까요?" ]', '[ "SAFETY", "VERIFICATION" ]', 'KERIS-1 Ch4.3 pp.179-191', 'MEDIUM', 'GPT', 'PREGENERATED', 6, 'MEDIUM', 'ACTIVE', TRUE)
INSERT INTO private.question_answer_keys (question_id, answer_payload, explanation) VALUES
    ('ae8d7e0d-89d9-3d3d-aa4b-b42e59aec305', 'true', 'KERIS 1권은 번역 앱, 카메라 앱, 인공지능 스피커 같은 생활 속 사례를 통해 인공지능을 이해하도록 안내해요. 다음에도 먼저 인공지능의 특징을 떠올려 보세요.'),
    ('0031da4f-c47a-3cad-b07a-1fd5862c9782', 'false', '빠른 계산만 하는 도구와, 데이터를 보고 분류하거나 추천하는 인공지능은 같지 않아요. 비슷한 장면에서도 인공지능의 특징을 먼저 살펴보세요.'),
    ('86fcf72b-bbb4-3287-a9d8-c52062064cf7', '"꽃을 구별해 주는 카메라 앱"', '생활 속 인공지능은 보거나 듣거나 비교해 판단하는 기능을 갖는 경우가 많아요. 헷갈릴 때는 인공지능의 특징을 다시 생각해 보세요.'),
    ('c25fe073-0389-3ba9-9954-38ce388e8805', '"선의 특징을 보고 무엇인지 짐작해요."', 'Quick Draw 같은 활동은 인공지능이 그림의 특징을 보고 추정한다는 점을 보여 줘요. 같은 활동이 나오면 인공지능의 특징을 먼저 적어 보세요.'),
    ('6feffb52-8d58-325d-93c6-8c14764a4fdb', '"이 도구는 무엇을 도와줄까?"', '도구의 모양보다 어떤 일을 하는지 묻는 질문이 더 중요해요. 고를 때도 인공지능의 특징을 먼저 따져 보세요.'),
    ('fb67594d-a460-3fd6-8867-31fda2ba710a', '"기능"', '인공지능인지 판단할 때는 어떤 기능을 수행하는지 보는 습관이 중요해요. 비교할 때는 인공지능의 특징을 먼저 보세요.'),
    ('1d56b048-e383-3b0c-8191-2a7f4d0163bc', '"비교"', '비교해 보면 여러 도구에서 공통으로 보이는 인공지능의 특징을 찾기 쉬워요. 판단하기 전에 인공지능의 특징을 먼저 확인해 보세요.'),
    ('54252005-07fd-3e4b-a1c4-404908c372ae', '"도구 기능부터 살펴보자고 해."', '겉모양보다 스스로 인식하거나 추천하는 기능이 있는지 살펴보는 것이 더 중요해요. 답을 찾기 전에 인공지능의 특징을 다시 보세요.'),
    ('a2d85886-ca7a-3a77-a5d2-b3e010e1b700', '"비슷한 그림은 헷갈릴 수 있다고 생각하면 돼요."', '이런 활동은 인공지능이 그림의 특징을 보고 짐작한다는 점과 한계를 함께 보여 줘요. 핵심은 인공지능의 특징을 먼저 챙기는 거예요.'),
    ('9b9656ad-fc90-3f1f-ad17-f8491b60347b', '"누구를 돕고 어떤 문제를 풀지 먼저 정해요."', '인공지능 아이디어를 정할 때는 누구를 돕고 어떤 문제를 풀지부터 분명히 해야 해요. 결국 인공지능의 특징을 먼저 살피는 거예요.'),
